@strawberry.input
class ProductFilterInput:
    min_price: Optional[float] = None
    max_price: Optional[float] = None
    seller_id: Optional[int] = None
    category_id: Optional[int] = None
    search: Optional[str] = None
    in_stock: Optional[bool] = None


@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info: Info,
        filter: Optional[ProductFilterInput] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> list[Product]:
        session: Session = info.context["session"]
        query = session.query(ProductModel).options(
            joinedload(ProductModel.seller),
            joinedload(ProductModel.reviews),
            joinedload(ProductModel.images),
            joinedload(ProductModel.categories),
        )

        if filter:
            if filter.min_price is not None:
                query = query.filter(ProductModel.price >= filter.min_price)
            if filter.max_price is not None:
                query = query.filter(ProductModel.price <= filter.max_price)
            if filter.seller_id is not None:
                query = query.filter(ProductModel.seller_id == filter.seller_id)
            if filter.search is not None:
                search_term = f"%{filter.search}%"
                query = query.filter(
                    (ProductModel.name.ilike(search_term))
                    | (ProductModel.description.ilike(search_term))
                )
            if filter.in_stock is not None:
                if filter.in_stock:
                    query = query.filter(ProductModel.stock > 0)
                else:
                    query = query.filter(ProductModel.stock == 0)
            if filter.category_id is not None:
                query = query.filter(
                    ProductModel.categories.any(CategoryModel.id == filter.category_id)
                )

        if offset is not None:
            query = query.offset(offset)
        if limit is not None:
            query = query.limit(limit)

        products = query.all()
        return [_product_from_model(p) for p in products]

    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[Product]:
        session: Session = info.context["session"]
        product_model = (
            session.query(ProductModel)
            .options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.images),
                joinedload(ProductModel.categories),
            )
            .get(id)
        )
        if not product_model:
            return None
        return _product_from_model(product_model)

    @strawberry.field
    def sellers(self, info: Info) -> list[Seller]:
        session: Session = info.context["session"]
        sellers = session.query(SellerModel).all()
        return [_seller_from_model(s) for s in sellers]

    @strawberry.field
    def seller(self, info: Info, id: int) -> Optional[Seller]:
        session: Session = info.context["session"]
        seller_model = session.query(SellerModel).get(id)
        if not seller_model:
            return None
        return _seller_from_model(seller_model)

    @strawberry.field
    def categories(self, info: Info, root_only: bool = False) -> list[Category]:
        session: Session = info.context["session"]
        query = session.query(CategoryModel)
        if root_only:
            query = query.filter(CategoryModel.parent_id.is_(None))
        cats = query.all()
        return [_category_from_model(c) for c in cats]

    @strawberry.field
    def category(self, info: Info, id: int) -> Optional[Category]:
        session: Session = info.context["session"]
        cat_model = session.query(CategoryModel).get(id)
        if not cat_model:
            return None
        return _category_from_model(cat_model)

    @strawberry.field
    def reviews(self, info: Info, product_id: Optional[int] = None) -> list[Review]:
        session: Session = info.context["session"]
        query = session.query(ReviewModel)
        if product_id is not None:
            query = query.filter(ReviewModel.product_id == product_id)
        reviews = query.all()
        return [_review_from_model(r) for r in reviews]


@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_seller(self, info: Info, input: CreateSellerInput) -> Seller:
        session: Session = info.context["session"]
        seller = SellerModel(
            name=input.name,
            email=input.email,
            rating=input.rating,
            description=input.description,
        )
        session.add(seller)
        session.commit()
        session.refresh(seller)
        return _seller_from_model(seller)

    @strawberry.mutation
    def create_category(self, info: Info, input: CreateCategoryInput) -> Category:
        session: Session = info.context["session"]
        category = CategoryModel(
            name=input.name,
            description=input.description,
            parent_id=input.parent_id,
        )
        session.add(category)
        session.commit()
        session.refresh(category)
        return _category_from_model(category)

    @strawberry.mutation
    def create_product(self, info: Info, input: CreateProductInput) -> Product:
        session: Session = info.context["session"]
        product = ProductModel(
            name=input.name,
            description=input.description,
            price=input.price,
            stock=input.stock,
            seller_id=input.seller_id,
        )
        if input.category_ids:
            categories = (
                session.query(CategoryModel)
                .filter(CategoryModel.id.in_(input.category_ids))
                .all()
            )
            product.categories = categories

        session.add(product)
        session.commit()
        session.refresh(product)

        # Reload with all relations
        product = (
            session.query(ProductModel)
            .options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.images),
                joinedload(ProductModel.categories),
            )
            .get(product.id)
        )
        return _product_from_model(product)

    @strawberry.mutation
    def create_review(self, info: Info, input: CreateReviewInput) -> Review:
        session: Session = info.context["session"]
        review = ReviewModel(
            product_id=input.product_id,
            reviewer_name=input.reviewer_name,
            rating=input.rating,
            title=input.title,
            comment=input.comment,
        )
        session.add(review)
        session.commit()
        session.refresh(review)
        return _review_from_model(review)

    @strawberry.mutation
    def create_image(self, info: Info, input: CreateImageInput) -> Image:
        session: Session = info.context["session"]
        image = ImageModel(
            product_id=input.product_id,
            url=input.url,
            alt_text=input.alt_text,
            is_primary=1 if input.is_primary else 0,
        )
        session.add(image)
        session.commit()
        session.refresh(image)
        return _image_from_model(image)

    @strawberry.mutation
    def delete_product(self, info: Info, id: int) -> bool:
        session: Session = info.context["session"]
        product = session.query(ProductModel).get(id)
        if not product:
            return False
        session.delete(product)
        session.commit()
        return True

    @strawberry.mutation
    def update_product_stock(self, info: Info, id: int, stock: int) -> Optional[Product]:
        session: Session = info.context["session"]
        product = (
            session.query(ProductModel)
            .options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.images),
                joinedload(ProductModel.categories),
            )
            .get(id)
        )
        if not product:
            return None
        product.stock = stock
        session.commit()
        session.refresh(product)
        return _product_from_model(product)


def get_context():
    session = SessionLocal()
    try:
        yield {"session": session}
    finally:
        session.close()


async def get_context_async():
    session = SessionLocal()
    return {"session": session}


schema = strawberry.Schema(query=Query, mutation=Mutation)
graphql_app = GraphQLRouter(schema, context_getter=get_context_async)

app = FastAPI(title="Product GraphQL API")
app.include_router(graphql_app, prefix="/graphql")


